// Pull both runs' `forall|i|` ensures into the proof context with their
// explicit triggers so the two quantifiers line up.  Each conjunct is a
// direct restatement of one ensures clause, so Verus discharges it
// without further hints.
assert(forall|i: int|
    #![trigger post1_self_.page_array@[i]]
    #![trigger pre_self_.page_array@[i]]
    0 <= i < NUM_PAGES && i != index
        ==> post1_self_.page_array@[i] =~= pre_self_.page_array@[i]);
assert(forall|i: int|
    #![trigger post2_self_.page_array@[i]]
    #![trigger pre_self_.page_array@[i]]
    0 <= i < NUM_PAGES && i != index
        ==> post2_self_.page_array@[i] =~= pre_self_.page_array@[i]);

// Pointwise: at every i in 0..NUM_PAGES, the two runs' pages agree.
// Case-split on whether i is the modified index.
assert forall|i: int| 0 <= i < NUM_PAGES
    implies post1_self_.page_array@[i] =~= post2_self_.page_array@[i]
by {
    if i == index as int {
        // At `index` every field of `Page` is pinned by the per-field
        // ensures to either `pre_self_.page_array@[index as int].<field>`
        // or the `ref_count` parameter, so each field of `post1_self_`'s
        // page at `index` equals the corresponding field of `post2_self_`'s
        // page at `index`, and struct extensionality (`=~=`) closes it.
    }
    // Otherwise i != index, and the two pulled-up foralls give
    //   post1_self_.page_array@[i] =~= pre_self_.page_array@[i]
    //   post2_self_.page_array@[i] =~= pre_self_.page_array@[i]
    // whose transitive composition is the goal.
}

// Sequence extensionality lifts the pointwise equality to the full
// `.view()` of the page_array, which is what `det_set_ref_count_equal`
// needs to relate the two runs.
assert(post1_self_.page_array@ =~= post2_self_.page_array@);
